@startuml
skinparam packageStyle rectangle

package "edu" {
    package "cmu" {
        package "pocketsphinx" {
            package "models" {
                class BuildConfig <<C>> 

                ' R appears to be another component/class in models namespace
                note right of BuildConfig : C\nR

                % Hide default members for cleaner look like original
                hide empty methods
                hide circle on classes
            }

            folder pocketsphinx as p2 #LightBlue

            link -[hidden]- buildconfig -- r
        }

        folder cmu as c2

        link -[hidden]- pocketsphinx -- c2
    }

    folder edu as e1

    link -[hidden]- cmu -- e1
}


title MODELS's Class Diagram



note bottom: PlantUML diagram generated by SketchIt! (https://bitbucket.org/pmesmeur/sketch.it)\nFor more information about this tool, please contact philippe.mesmeur@gmail.com 

@enduml
